import sys
input = sys.stdin.read

def solve(a, b):
    if a == b:
        return 0
    if b == 0:
        return -1
    if b == 1:
        return 1 if a == 0 else -1

    aa = bin(a).count('1')
    bb = bin(b - 1).count('1')

    if aa > bb:
        return 2
    else:
        return bb - aa + 1

def main():
    data = input().split()
    t = int(data[0])
    results = []
    idx = 1
    for _ in range(t):
        a = int(data[idx])
        b = int(data[idx + 1])
        results.append(solve(a, b))
        idx += 2

    # Print all results at once to optimize I/O
    sys.stdout.write("\n".join(map(str, results)) + "\n")

if __name__ == "__main__":
    main()

