#include <stdio.h>
#include <stdint.h>

int popcountll(int64_t x) {
    int count = 0;
    while (x) {
        count += x & 1;
        x >>= 1;
    }
    return count;
}

void solve() {
    int64_t a, b;
    scanf("%lld %lld", &a, &b);

    if (a == b) {
        printf("0\n");
        return;
    }

    if (b == 0) {
        printf("-1\n");
        return;
    }

    if (b == 1) {
        if (a == 0) {
            printf("1\n");
        } else {
            printf("-1\n");
        }
        return;
    }

    int aa = popcountll(a);
    int bb = popcountll(b - 1);

    if (aa > bb) {
        printf("2\n");
    } else {
        printf("%d\n", bb - aa + 1);
    }
}

int main() {
    int t;
    scanf("%d", &t);

    while (t--) {
        solve();
    }

    return 0;
}

