const readline = require("readline");

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

let input = [];
rl.on("line", (line) => {
    input.push(line);
});

rl.on("close", () => {
    let T = parseInt(input[0]);
    let results = [];

    function countSetBits(n) {
        let count = 0n;
        while (n > 0n) {
            count += (n & 1n);
            n >>= 1n;
        }
        return count;
    }

    for (let i = 1; i <= T; i++) {
        let [a, b] = input[i].split(" ").map(BigInt);

        if (a === b) {
            results.push(0);
            continue;
        }

        if (b === 0n) {
            results.push(-1);
            continue;
        }

        if (b === 1n) {
            results.push(a === 0n ? 1 : -1);
            continue;
        }

        let aa = countSetBits(a);
        let bb = countSetBits(b - 1n);

        if (aa > bb) {
            results.push(2);
        } else {
            results.push(Number(bb - aa + 1n));
        }
    }

    console.log(results.join("\n"));
});
